const r = $input.item.json;
const ct = r.content || [];
let t = '';
for (let i = ct.length - 1; i >= 0; i--) { if (ct[i].type === 'text' && ct[i].text) { t = ct[i].text; break; } }

let p;
try {
  const m = t.match(/\{[\s\S]*\}/);
  p = m ? JSON.parse(m[0]) : {};
} catch(e) { p = {}; }

const chatId = $('Vocal Telegram').item.json.message.chat.id;

return { json: {
  entreprise: p.entreprise || 'Inconnu',
  prenom: p.prenom_client || '',
  prestation: p.prestation || 'Formation',
  montant: Number(p.montant) || 0,
  description: p.description || '',
  chatId: String(chatId)
}};

const ext = $('Extract Info').item.json;
const nr = $input.item.json;
const lead = (nr.results || [])[0];
const props = lead ? lead.properties || {} : {};

const gt = (p) => {
  if (!p) return '';
  if (p.title) return p.title.map(t => t.plain_text || '').join('');
  if (p.rich_text) return p.rich_text.map(t => t.plain_text || '').join('');
  if (p.email) return p.email || '';
  return '';
};

const pageId = lead ? lead.id : '';
const email = gt(props['Email']);
const contact = gt(props['Contact principal']);
const societe = gt(props['Nom entreprise']) || ext.entreprise;
const tel = gt(props['TĂ©lĂ©phone']);

// Generate devis number
const now = new Date();
const year = now.getFullYear();
const num = String(Math.floor(Math.random() * 900) + 100);
const devisNum = 'EXC-' + year + '-' + num;

const tva = Math.round(ext.montant * 0.077);
const ttc = ext.montant + tva;

return { json: {
  pageId,
  email,
  contact: contact || ext.prenom,
  prenom: ext.prenom || contact.split(' ')[0] || '',
  societe,
  tel,
  prestation: ext.prestation,
  montant: ext.montant,
  tva,
  ttc,
  description: ext.description,
  devisNum,
  chatId: ext.chatId
}};
